// Auto-generated by r2factor. Manual edits will be overwritten on next split.

use super::super::group_processing::{
    process_cardioid, process_dba, process_multisub_group, process_speaker_group,
};
use super::super::pipeline::{PipelineStepId, PipelineStepStatus};
use super::super::speaker_eq::process_single_speaker;
use super::super::types::{RoomConfig, SpeakerConfig};
use super::misc::generic_channel_progress_iterations;
use super::room_optimization_progress::RoomOptimizationProgress;
use super::room_optimization_progress::send_progress;
use super::types::MixedModeResult;
use super::types::SharedPipelineObserver;
use super::types::SpeakerProcessResult;
use crate::error::Result;
use log::info;
use std::collections::HashMap;
use std::path::Path;
use std::sync::Arc;

pub(super) fn process_generic_channels(
    channels_to_process: Vec<(String, SpeakerConfig)>,
    config: &RoomConfig,
    sample_rate: f64,
    output_dir: Option<&Path>,
    shared_mean_spl: Option<f64>,
    probe_arrival_overrides: Option<&HashMap<String, f64>>,
    observer_shared: &SharedPipelineObserver,
) -> Result<Vec<SpeakerProcessResult>> {
    let total_speakers = channels_to_process.len();

    send_progress(
        observer_shared,
        PipelineStepId::GenericChannelOptimization,
        PipelineStepStatus::Started,
        &RoomOptimizationProgress {
            current_speaker: String::new(),
            speaker_index: 0,
            total_speakers,
            iteration: 0,
            max_iterations: 0,
            loss: 0.0,
            overall_progress: 0.0,
            message: Some(format!(
                "Starting optimization for {} channels",
                total_speakers
            )),
            epa_preference: None,
            step_id: None,
            step_status: None,
        },
    )?;

    // Compute actual DE generation budget for accurate progress display.
    // The DE callback reports generation numbers, not function evals.
    // Formula mirrors optim_de::derive_de_budget.
    let max_iterations = generic_channel_progress_iterations(config);

    let mut results: Vec<SpeakerProcessResult> = Vec::with_capacity(total_speakers);
    for (speaker_idx, (channel_name, speaker_config)) in channels_to_process.into_iter().enumerate()
    {
        info!("Processing channel: {}", channel_name);

        send_progress(
            observer_shared,
            PipelineStepId::GenericChannelOptimization,
            PipelineStepStatus::InProgress,
            &RoomOptimizationProgress {
                current_speaker: channel_name.clone(),
                speaker_index: speaker_idx,
                total_speakers,
                iteration: 0,
                max_iterations: 0,
                loss: 0.0,
                overall_progress: speaker_idx as f64 / total_speakers as f64,
                message: Some(format!("Processing channel: {}", channel_name)),
                epa_preference: None,
                step_id: None,
                step_status: None,
            },
        )?;

        let eq_callback: Option<crate::optim::OptimProgressCallback> = {
            let observer = Arc::clone(observer_shared);
            let name = channel_name.clone();
            let si = speaker_idx;
            let ts = total_speakers;
            let mi = max_iterations;
            Some(Box::new(move |iter: usize, loss: f64, epa: Option<f64>| {
                let base_progress = si as f64 / ts as f64;
                let speaker_progress = if mi > 0 { iter as f64 / mi as f64 } else { 0.0 };
                let overall = (base_progress + speaker_progress / ts as f64).min(1.0);

                match send_progress(
                    &observer,
                    PipelineStepId::GenericChannelOptimization,
                    PipelineStepStatus::InProgress,
                    &RoomOptimizationProgress {
                        current_speaker: name.clone(),
                        speaker_index: si,
                        total_speakers: ts,
                        iteration: iter,
                        max_iterations: mi,
                        loss,
                        overall_progress: overall,
                        message: None,
                        epa_preference: epa,
                        step_id: None,
                        step_status: None,
                    },
                ) {
                    Ok(()) => crate::de::CallbackAction::Continue,
                    Err(_) => crate::de::CallbackAction::Stop,
                }
            }))
        };

        let result = process_speaker_internal(
            &channel_name,
            &speaker_config,
            config,
            sample_rate,
            output_dir,
            eq_callback,
            shared_mean_spl,
            probe_arrival_overrides,
        );

        match result {
            Ok((
                chain,
                pre_score,
                post_score,
                initial_curve,
                final_curve,
                biquads,
                mean_spl,
                arrival_time_ms,
                fir_coeffs,
            )) => {
                send_progress(
                    observer_shared,
                    PipelineStepId::GenericChannelOptimization,
                    PipelineStepStatus::InProgress,
                    &RoomOptimizationProgress {
                        current_speaker: channel_name.clone(),
                        speaker_index: speaker_idx,
                        total_speakers,
                        iteration: 0,
                        max_iterations: 0,
                        loss: post_score,
                        overall_progress: (speaker_idx + 1) as f64 / total_speakers as f64,
                        message: Some(format!(
                            "Channel {}: {:.4} -> {:.4}",
                            channel_name, pre_score, post_score
                        )),
                        epa_preference: None,
                        step_id: None,
                        step_status: None,
                    },
                )?;

                results.push(Ok((
                    channel_name,
                    chain,
                    pre_score,
                    post_score,
                    initial_curve,
                    final_curve,
                    biquads,
                    mean_spl,
                    arrival_time_ms,
                    fir_coeffs,
                )));
            }
            Err(e) => {
                results.push(Err(e));
            }
        }
    }

    send_progress(
        observer_shared,
        PipelineStepId::GenericChannelOptimization,
        PipelineStepStatus::Completed,
        &RoomOptimizationProgress {
            current_speaker: String::new(),
            speaker_index: total_speakers,
            total_speakers,
            iteration: 0,
            max_iterations: 0,
            loss: 0.0,
            overall_progress: 0.90,
            message: Some(format!("Optimized {} channels", total_speakers)),
            epa_preference: None,
            step_id: None,
            step_status: None,
        },
    )?;

    Ok(results)
}

/// Process a single speaker (simple or group)
///
/// Returns: (DSP chain, pre_score, post_score, initial_curve, final_curve, biquads, mean_spl, arrival_time_ms)
///
/// `probe_arrival_overrides` — optional per-channel probe-based arrival times
/// (from the delay-detection UI step). When present and the channel name has a
/// matching entry, this overrides the WAV-onset fallback inside
/// `process_single_speaker`.
#[allow(clippy::too_many_arguments)]
pub(super) fn process_speaker_internal(
    channel_name: &str,
    speaker_config: &SpeakerConfig,
    room_config: &RoomConfig,
    sample_rate: f64,
    output_dir: Option<&Path>,
    callback: Option<crate::optim::OptimProgressCallback>,
    shared_mean_spl: Option<f64>,
    probe_arrival_overrides: Option<&HashMap<String, f64>>,
) -> Result<MixedModeResult> {
    let output_dir = output_dir.unwrap_or(Path::new("."));

    match speaker_config {
        SpeakerConfig::Single(source) => {
            let probe_arrival_ms =
                probe_arrival_overrides.and_then(|m| m.get(channel_name).copied());
            process_single_speaker(
                channel_name,
                source,
                room_config,
                sample_rate,
                output_dir,
                callback,
                probe_arrival_ms,
                shared_mean_spl,
            )
        }
        SpeakerConfig::Group(group) => {
            process_speaker_group(channel_name, group, room_config, sample_rate, output_dir)
        }
        SpeakerConfig::MultiSub(group) => {
            process_multisub_group(channel_name, group, room_config, sample_rate, output_dir)
        }
        SpeakerConfig::Dba(config) => {
            process_dba(channel_name, config, room_config, sample_rate, output_dir)
        }
        SpeakerConfig::Cardioid(config) => {
            process_cardioid(channel_name, config, room_config, sample_rate, output_dir)
        }
        SpeakerConfig::SupportingSource(_group) => Err(crate::error::AutoeqError::InvalidConfiguration {
            message: format!(
                "Supporting source channel '{}' must be processed by the supporting-source workflow, not the generic single-speaker path",
                channel_name
            ),
        }),
    }
}
